-- Complete product reimport from produktefinal.csv (v3)
-- Uses auth.users fallback if user_roles is empty

DELETE FROM public.invoice_templates;

DO $$
DECLARE
  owner_uid uuid;
BEGIN
  SELECT user_id INTO owner_uid FROM public.user_roles WHERE role = 'administrator' LIMIT 1;
